  4→// Generate unique email per test run to avoid collisions with existing data
  5→const testEmail = `e2e-${Date.now()}@example.com`;
  6→const testPassword = "securepassword123";
  7→
  8→// Helper: fill the registration form.
  9→// The password-toggle.js progressive enhancement removes the confirm password
 10→// field and replaces it with a hidden input that mirrors the password value.
 11→// We wait for the page to settle, then only fill the confirm field if it's
 12→// still visible (i.e., JS hasn't run or hasn't removed it yet).
 13→async function fillRegistrationForm(
 14→  page: Page,
 15→  email: string,
 16→  password: string
 17→) {
 18→  // Wait for the page to fully load (including deferred scripts)
 19→  await page.waitForLoadState("networkidle");
 20→
 21→  await page.getByLabel("Email").fill(email);
 22→  await page.getByLabel("Password", { exact: true }).fill(password);
 23→
 24→  // After JS runs, the confirm field may be removed.
 25→  // Check if it's still in the DOM and visible.
 26→  const confirmCount = await page
 27→    .getByLabel("Confirm password")
 28→    .count();
 29→  if (confirmCount > 0) {
 30→    const isVisible = await page
 31→      .getByLabel("Confirm password")
 32→      .isVisible();
 33→    if (isVisible) {
 34→      await page.getByLabel("Confirm password").fill(password);
 35→    }
 36→  }
 37→
 38→  await page.getByRole("button", { name: "Create account" }).click();
 39→}
 40→
 41→test.describe("Core user journey", () => {
 42→  test("visitor sees register and sign in links on index page", async ({
 43→    page,
 44→  }) => {
 45→    await page.goto("/");
 46→
 47→    await expect(page).toHaveTitle("Todo List");
 48→    await expect(
 49→      page.getByRole("heading", { name: "Welcome" })
 50→    ).toBeVisible();
 51→    await expect(
 52→      page.getByRole("link", { name: "Create account" }).first()
 53→    ).toBeVisible();
 54→    await expect(
 55→      page.getByRole("link", { name: "Sign in" }).first()
 56→    ).toBeVisible();
 57→  });
 58→
 59→  test("full user journey: register, add, complete, delete, logout", async ({
 60→    page,
 61→  }) => {
 62→    // 1. Visit index and click Create account (the visible hero CTA)
 63→    await page.goto("/");
 64→    await page
 65→      .locator(".landing-hero")
 66→      .getByRole("link", { name: "Create account" })
 67→      .click();
 68→    await expect(page).toHaveURL(/\/register/);
 69→
 70→    // 2. Fill registration form and submit
 71→    await fillRegistrationForm(page, testEmail, testPassword);
 72→
 73→    // Should redirect to login after registration
 74→    await expect(page).toHaveURL(/\/login/);
 75→
 76→    // 3. Log in
 77→    await page.getByLabel("Email").fill(testEmail);
 78→    await page.getByLabel("Password").fill(testPassword);
 79→    await page.getByRole("button", { name: "Sign in" }).click();
 80→
 81→    // Should redirect to dashboard
 82→    await expect(page).toHaveURL(/\/dashboard/);
 83→    await expect(
 84→      page.getByRole("heading", { name: "Dashboard" })
 85→    ).toBeVisible();
 86→
 87→    // Navigate to todos page to manage todo items
 88→    await page.goto("/todos");
 89→
 90→    // 4. Add a todo
 91→    await page.getByLabel("New todo").fill("Buy groceries");
 92→    await page.getByRole("button", { name: "Add todo" }).click();
 93→
 94→    // The todo should appear in the list
 95→    await expect(page.getByText("Buy groceries")).toBeVisible();
 96→
 97→    // 5. Complete the todo (click the toggle button)
 98→    await page
 99→      .getByRole("button", { name: /Mark .+Buy groceries.+ as complete/ })
100→      .click();
101→
102→    // After toggling, the page should still show the todo
103→    // (either via HTMX swap or page reload)
104→    await expect(page.getByText("Buy groceries")).toBeVisible();
105→
106→    // 6. Delete the todo
107→    // The delete uses a <details>/<summary> confirmation pattern
108→    await page
109→      .locator('[aria-label*="Delete"][aria-label*="Buy groceries"]')
110→      .click();
111→    // Click the confirm delete button
112→    await page.getByRole("button", { name: "Yes" }).click();
113→
114→    // The todo should be removed
115→    await expect(page.getByText("Buy groceries")).not.toBeVisible();
116→
117→    // 7. Logout
